            "apn_settings" -> mapOf("message" to "Opening APN settings")
            "nfc_on" -> ControlExecutor.nfcOn(context)
            "nfc_off" -> ControlExecutor.nfcOff(context)
            "auto_update_on", "auto_update_off" -> mapOf("message" to "System update settings")


